// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Use a more robust HTML parser if available, but for this task, we'll use regex
	// Note: For production code, consider using golang.org/x/net/html

	content, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}

	// Extract title
	titleRegex := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	titleMatches := titleRegex.FindSubmatch(content)
	if len(titleMatches) > 1 {
		title = strings.TrimSpace(string(titleMatches[1]))
		title = stripHTMLTags(title)
	}

	// Extract description
	descriptionRegex := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["'](.*?)["']`)
	descriptionMatches := descriptionRegex.FindSubmatch(content)
	if len(descriptionMatches) > 1 {
		description = strings.TrimSpace(string(descriptionMatches[1]))
	}

	return title, description, nil
}

// stripHTMLTags removes HTML tags from a string.
func stripHTMLTags(s string) string {
	var result strings.Builder
	inTag := false
	for _, r := range s {
		switch r {
		case '<':
			inTag = true
		case '>':
			inTag = false
		default:
			if !inTag {
				result.WriteRune(r)
			}
		}
	}
	return result.String()
}

