	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if ctx.IsPost() {
		var req struct {
			URL string `json:"url"`
		}

		body := ctx.PostBody()
		if err := json.Unmarshal(body, &req); err != nil {
			ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
			return
		}

		targetURL := strings.TrimSpace(req.URL)
		if targetURL == "" {
			ctx.Error("URL is required", fasthttp.StatusBadRequest)
			return
		}

		// Validate URL scheme
		parsedURL, err := url.Parse(targetURL)
		if err != nil {
			ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
			return
		}

		if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
			ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
			return
		}

		// Block private IP addresses
		if isPrivateIP(parsedURL.Hostname()) {
			ctx.Error("Private IP addresses are not allowed", fasthttp.StatusBadRequest)
			return
		}

		// Use fasthttp.Client to fetch with timeout
		client := &fasthttp.Client{
			Dial:                fasthttp.DialDualStack,
			ReadTimeout:         5 * time.Second,
			WriteTimeout:        5 * time.Second,
			MaxIdleConnDuration: 5 * time.Second,
			MaxConnsPerHost:     10,
		}

		freq := fasthttp.AcquireRequest()
		res := fasthttp.AcquireResponse()
		defer fasthttp.ReleaseRequest(freq)
		defer fasthttp.ReleaseResponse(res)

		freq.SetRequestURI(targetURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

		maxRedirectCounts := 3
		if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		if res.StatusCode() != fasthttp.StatusOK {
			ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
			return
		}

		bodyBytes := res.Body()
		if len(bodyBytes) == 0 {
			ctx.Error("Empty response body", fasthttp.StatusBadGateway)
			return
		}

		title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
		if err != nil {
			ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
			return
		}

		resp := PreviewResponse{
			Title:       title,
			Description: description,
		}

		ctx.SetContentType("application/json; charset=utf-8")
		if err := json.NewEncoder(ctx).Encode(resp); err != nil {
			ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// isPrivateIP checks if the hostname resolves to a private IP address.
func isPrivateIP(hostname string) bool {
	// Resolve hostname to IP addresses
	ips, err := netLookupIP(hostname)
	if err != nil {
		return true
	}

	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast() {
			return true
		}

		// Check for IPv4 private ranges
		if ipv4 := ip.To4(); ipv4 != nil {
			if ipv4[0] == 10 || ipv4[0] == 172 && (ipv4[1] >= 16 && ipv4[1] <= 31) || ipv4[0] == 192 && ipv4[1] == 168 {
				return true
			}
			if ipv4[0] == 127 {
				return true
			}
		}
	}

	return false
}

// netLookupIP is a wrapper for net.LookupIP that we can control.
func netLookupIP(host string) ([]net.IP, error) {
	// Use proper net.LookupIP function instead of dialing
	return net.LookupIP(host)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Use a more robust HTML parser if available, but for this task, we'll use regex
	// Note: For production code, consider using golang.org/x/net/html

	content, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}

	// Extract title
	titleRegex := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	titleMatches := titleRegex.FindSubmatch(content)
	if len(titleMatches) > 1 {
		title = strings.TrimSpace(string(titleMatches[1]))
		title = stripHTMLTags(title)
	}

	// Extract description
	descriptionRegex := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["'](.*?)["']`)
	descriptionMatches := descriptionRegex.FindSubmatch(content)
	if len(descriptionMatches) > 1 {
		description = strings.TrimSpace(string(descriptionMatches[1]))
	}

	return title, description, nil
}

// stripHTMLTags removes HTML tags from a string.
func stripHTMLTags(s string) string {
	var result strings.Builder
	inTag := false
	for _, r := range s {
		switch r {
		case '<':
			inTag = true
		case '>':
			inTag = false
		default:
			if !inTag {
				result.WriteRune(r)
			}
		}
	}
	return result.String()
}

