// isForbiddenIP checks if the hostname resolves to a forbidden IP address.
func isForbiddenIP(hostname string) bool {
	// Skip if hostname is empty
	if hostname == "" {
		return true
	}

	// Resolve hostname to IPs
	ips, err := net.DefaultResolver.LookupIPAddr(context.Background(), hostname)
	if err != nil {
		return true
	}

	for _, ip := range ips {
		if isForbiddenIPAddr(ip.IP) {
			return true
		}
	}

	return false
}

// isForbiddenIPAddr checks if the IP address is in forbidden ranges.
func isForbiddenIPAddr(ip net.IP) bool {
	// Localhost
	if ip.IsLoopback() {
		return true
	}

	// Private IPs
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && (ip4[1] >= 16 && ip4[1] <= 31) {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 0.0.0.0/8
		if ip4[0] == 0 {
			return true
		}
	}

	// Link-local
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// IPv6 mapped to IPv4
	if ip.To4() != nil {
		return isForbiddenIPAddr(ip.To4())
	}

	return false
}

import "context"

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			return title, description, nil
		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := token.Data

			if tagName == "title" {
				tokenizer.Next()
				if tokenizer.Token().Type == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			} else if tagName == "meta" {
				for _, attr := range token.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						for _, attr := range token.Attr {
							if attr.Key == "content" {
								description = attr.Val
								break
							}
						}
						break
					}
				}
			}
		}
	}
}

