// isPrivateIP checks if an IP is private, loopback, or link-local.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
		return true
	}

	private4 := []*net.IPNet{
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},    // 10.0.0.0/8
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)}, // 172.16.0.0/12
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)}, // 192.168.0.0/16
		{IP: net.ParseIP("127.0.0.0"), Mask: net.CIDRMask(8, 32)},    // 127.0.0.0/8
		{IP: net.ParseIP("0.0.0.0"), Mask: net.CIDRMask(8, 32)},      // 0.0.0.0/8
	}

	for _, cidr := range private4 {
		if cidr.Contains(ip) {
			return true
		}
	}

	return false
}

// netLookupIP performs a DNS lookup and returns IPv4 and IPv6 addresses.
func netLookupIP(host string) ([]net.IP, error) {
	addr, err := net.ResolveIPAddr("ip", host)
	if err != nil {
		return nil, err
	}
	return []net.IP{addr.IP}, nil
}

