// createSafeDialer creates a dialer that blocks unsafe addresses
func createSafeDialer() func(network, addr string) (net.Conn, error) {
	return func(network, addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, err
		}

		ip := net.ParseIP(host)
		if ip == nil {
			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}
			for _, ipAddr := range ips {
				if isLocalAddress(ipAddr) {
					return nil, fmt.Errorf("blocked access to private IP")
				}
			}
			ip = ips[0]
		} else if isLocalAddress(ip) {
			return nil, fmt.Errorf("blocked access to private IP")
		}

		return net.Dial(network, net.JoinHostPort(host, port))
	}
}

// isLocalHost checks if the host is a local hostname
func isLocalHost(host string) bool {
	if host == "localhost" || host == "127.0.0.1" || host == "::1" {
		return true
	}
	return false
}

// isLocalAddress checks if an IP address is private or local
func isLocalAddress(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast() {
		return true
	}

	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 || // 10.0.0.0/8
			ip4[0] == 172 && ip4[1] >= 16 && ip4[1] < 32 || // 172.16.0.0/12
			ip4[0] == 192 && ip4[1] == 168 || // 192.168.0.0/16
			ip4[0] == 127 // 127.0.0.0/8
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			return title, description, nil
		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := token.Data

			if tagName == "title" {
				tokenizer.Next()
				if tokenizer.Token().Type == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			} else if tagName == "meta" {
				for _, attr := range token.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						for _, attr := range token.Attr {
							if attr.Key == "content" {
								description = attr.Val
								break
							}
						}
						break
					}
				}
			}
		}
	}
}

