	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// RequestBody represents the expected JSON request body
type RequestBody struct {
	URL string `json:"url"`
}

// ResponseBody represents the JSON response structure
type ResponseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		FetchURLPreview(ctx)
	}

	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		fmt.Fprintf(&fasthttp.RequestCtx{}, "Error starting server: %v\n", err)
	}
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse the request body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error": "Invalid JSON"}`)
		return
	}

	// Validate the URL
	u, err := url.Parse(reqBody.URL)
	if err != nil || u.Scheme == "" || u.Host == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error": "Invalid URL"}`)
		return
	}

	// Ensure scheme is http or https
	if u.Scheme != "http" && u.Scheme != "https" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error": "Only http or https URLs are allowed"}`)
		return
	}

	// Create a fasthttp client with required settings
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return fasthttp.DialDualStack(addr)
		},
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
		MaxConnsPerHost: 1024,
	}

	// Prepare the HTTP request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

	// Perform the request with redirects
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	if err := client.DoRedirects(req, resp, 3); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(fmt.Sprintf(`{"error": "Failed to fetch URL: %v"}`, err))
		return
	}

	// Check response status
	statusCode := resp.StatusCode()
	if statusCode != fasthttp.StatusOK {
		ctx.SetStatusCode(statusCode)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(fmt.Sprintf(`{"error": "Unexpected status code: %d"}`, statusCode))
		return
	}

	// Read the body
	body := resp.Body()
	contentType := string(resp.Header.ContentType())

	// Only process HTML content
	if !strings.HasPrefix(contentType, "text/html") && !strings.Contains(contentType, "html") {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error": "Content is not HTML"}`)
		return
	}

	// Parse HTML and extract title and meta description
	title, description, err := parseHTML(body)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(fmt.Sprintf(`{"error": "Failed to parse HTML: %v"}`, err))
		return
	}

	// Create response
	response := ResponseBody{
		Title:       title,
		Description: description,
	}

	// Send JSON response
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(response)
}

func parseHTML(body []byte) (string, string, error) {
	reader := bytes.NewReader(body)
	tokenizer := html.NewTokenizer(reader)

	var title string
	var description string

	for {
		tt := tokenizer.Next()

		switch tt {
		case html.ErrorToken:
			if tokenizer.Err() != io.EOF {
				return "", "", tokenizer.Err()
			}
			return title, description, nil

		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := token.Data

			if tagName == "title" {
				tt = tokenizer.Next()
				if tt == html.TextToken {
					title = strings.TrimSpace(string(tokenizer.Text()))
				}
			} else if tagName == "meta" {
				var name, content string
				for _, attr := range token.Attr {
					if attr.Key == "name" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}

				if name == "description" || name == "og:description" {
					description = content
				}
			}

		case html.EndTagToken:
			// No special handling needed
		}
	}
}

