// isPrivateIP checks if an IP is private, loopback, or reserved.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast() || ip.IsUnspecified() {
		return true
	}

	// IPv4 private ranges
	if ipv4 := ip.To4(); ipv4 != nil {
		// 10.0.0.0/8
		if ipv4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ipv4[0] == 172 && (ipv4[1] >= 16 && ipv4[1] <= 31) {
			return true
		}
		// 192.168.0.0/16
		if ipv4[0] == 192 && ipv4[1] == 168 {
			return true
		}
		// 127.0.0.0/8 (loopback)
		if ipv4[0] == 127 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ipv4[0] == 169 && ipv4[1] == 254 {
			return true
		}
		// 0.0.0.0/8 (current network)
		if ipv4[0] == 0 {
			return true
		}
	}

	// IPv6 private ranges
	if len(ip) == 16 {
		// fc00::/7 (unique local address)
		if ip[0] >= 0xfc && ip[0] <= 0xfd {
			return true
		}
		// fe80::/10 (link-local)
		if ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
			return true
		}
		// ::1 (loopback)
		if ip.String() == "::1" {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			return title, description, nil
		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := token.Data

			if tagName == "title" {
				tokenizer.Next()
				if tokenizer.Token().Type == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			} else if tagName == "meta" {
				for _, attr := range token.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						for _, attr := range token.Attr {
							if attr.Key == "content" {
								description = attr.Val
								break
							}
						}
						break
					}
				}
			}
		}
	}
}

