// isPrivateIP checks if an IP address is private
func isPrivateIP(ip net.IP) bool {
	// IPv4 private ranges
	privateBlocks := []*net.IPNet{
		netCIDR("10.0.0.0/8"),
		netCIDR("172.16.0.0/12"),
		netCIDR("192.168.0.0/16"),
		netCIDR("127.0.0.0/8"),   // loopback
		netCIDR("169.254.0.0/16"), // link-local
	}

	for _, block := range privateBlocks {
		if block.Contains(ip) {
			return true
		}
	}

	// IPv6 local addresses
	if ip.To4() == nil && (ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified()) {
		return true
	}

	return false
}

func netCIDR(cidr string) *net.IPNet {
	_, block, err := net.ParseCIDR(cidr)
	if err != nil {
		panic("invalid CIDR: " + cidr)
	}
	return block
}

// parseHTML is a simple parser to extract title and meta description
// In a production environment, use a proper HTML parser like "github.com/PuerkitoBio/goquery"
func parseHTML(body []byte) (string, string) {
	html := strings.ToLower(string(body))

	// Extract title
	title := extractTagContent(html, "<title>", "</title>")

	// Extract description
	description := ""
	if desc := extractMetaContent(html, "name=\"description\""); desc != "" {
		description = desc
	} else if desc := extractMetaContent(html, "property=\"og:description\""); desc != "" {
		description = desc
	}

	return title, description
}

func extractTagContent(html, start, end string) string {
	startIdx := strings.Index(html, start)
	if startIdx == -1 {
		return ""
	}

	startIdx += len(start)
	endIdx := strings.Index(html[startIdx:], end)
	if endIdx == -1 {
		return ""
	}

	return strings.TrimSpace(html[startIdx : startIdx+endIdx])
}

func extractMetaContent(html, metaAttr string) string {
	metaStart := "meta " + metaAttr
	startIdx := strings.Index(html, metaStart)
	if startIdx == -1 {
		return ""
	}

	// Find content attribute
	contentStart := strings.Index(html[startIdx:], "content=\"")
	if contentStart == -1 {
		return ""
	}

	contentStart += startIdx + len("content=\"")
	endIdx := strings.Index(html[contentStart:], "\"")
	if endIdx == -1 {
		return ""
	}

	return strings.TrimSpace(html[contentStart : contentStart+endIdx])
}

