// createSafeDialer creates a dialer that blocks unsafe addresses
func createSafeDialer() func(addr string) (net.Conn, error) {
	dialer := &fasthttp.Dialer{
		Timeout:               10 * time.Second,
		ReadTimeout:           10 * time.Second,
		WriteTimeout:          10 * time.Second,
		DualStack:             true,
		Concurrency:           10,
		KeepAliveInterval:     10 * time.Second,
		MaxConnsPerHost:       10,
		MaxIdleConnDuration:   10 * time.Second,
		ResolveRetryAttempts:  3,
		ResolveRetryDelay:     1 * time.Second,
	}

	return func(addr string) (net.Conn, error) {
		conn, err := dialer.Dial(addr)
		if err != nil {
			return nil, err
		}

		// Verify the connection is not to a local/loopback address
		remoteAddr := conn.RemoteAddr().String()
		host, _, err := net.SplitHostPort(remoteAddr)
		if err == nil && isLocalHost(host) {
			conn.Close()
			return nil, fmt.Errorf("connection to localhost is not allowed")
		}

		return conn, nil
	}
}

// isLocalHost checks if the hostname resolves to a loopback or private address
func isLocalHost(hostname string) bool {
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

	// Check against IP addresses
	ip := net.ParseIP(hostname)
	if ip != nil {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
			return true
		}
	}

	// Try to resolve the hostname to IPs
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If resolution fails, consider it unsafe
		return true
	}

	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			return title, description, nil
		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := token.Data

			if tagName == "title" {
				tokenizer.Next()
				if tokenizer.Token().Type == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			} else if tagName == "meta" {
				for _, attr := range token.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						for _, attr := range token.Attr {
							if attr.Key == "content" {
								description = attr.Val
								break
							}
						}
						break
					}
				}
			}
		}
	}
}

