// resolveIP resolves the hostname to an IP address
func resolveIP(u string) (net.IP, error) {
	parsedURL, err := url.Parse(u)
	if err != nil {
		return nil, err
	}

	host := parsedURL.Hostname()
	if host == "" {
		return nil, fmt.Errorf("empty hostname")
	}

	ips, err := net.DefaultResolver.LookupIPAddr(context.Background(), host)
	if err != nil {
		return nil, err
	}

	if len(ips) == 0 {
		return nil, fmt.Errorf("no IP addresses found for %s", host)
	}

	return ips[0].IP, nil
}

// isDangerousIP checks if the IP is local, loopback, or private
func isDangerousIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Check for loopback addresses
	if ip.IsLoopback() {
		return true
	}

	// Check for link-local unicast
	if ip.IsLinkLocalUnicast() {
		return true
	}

	// Check for link-local multicast
	if ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for private IP ranges
	privateCIDRs := []*net.IPNet{
		net.MustParseCIDR("10.0.0.0/8"),      // Class A private network
		net.MustParseCIDR("172.16.0.0/12"),   // Class B private network
		net.MustParseCIDR("192.168.0.0/16"),  // Class C private network
		net.MustParseCIDR("127.0.0.0/8"),     // Localhost
		net.MustParseCIDR("0.0.0.0/32"),      // Current network
		net.MustParseCIDR("169.254.0.0/16"),  // Link-local
	}

	for _, cidr := range privateCIDRs {
		if cidr.Contains(ip) {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			return title, description, nil
		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := token.Data

			if tagName == "title" {
				tokenizer.Next()
				if tokenizer.Token().Type == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			} else if tagName == "meta" {
				for _, attr := range token.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						for _, attr := range token.Attr {
							if attr.Key == "content" {
								description = attr.Val
								break
							}
						}
						break
					}
				}
			}
		}
	}
}

