// Function to extract title and meta description from HTML
func extractMetaData(htmlContent string) (string, string) {
	title := ""
	description := ""

	// Simple extraction logic using strings
	// Find title tag
	titleStart := strings.Index(strings.ToLower(htmlContent), "<title>")
	titleEnd := strings.Index(strings.ToLower(htmlContent), "</title>")
	if titleStart != -1 && titleEnd != -1 && titleEnd > titleStart {
		title = strings.TrimSpace(htmlContent[titleStart+7 : titleEnd])
	}

	// Find meta description
	descriptionStart := strings.Index(strings.ToLower(htmlContent), `<meta name="description"`)
	if descriptionStart == -1 {
		descriptionStart = strings.Index(strings.ToLower(htmlContent), `<meta property="og:description"`)
	}

	if descriptionStart != -1 {
		descriptionEnd := strings.Index(htmlContent[descriptionStart:], ">")
		if descriptionEnd != -1 {
			descriptionTag := htmlContent[descriptionStart : descriptionStart+descriptionEnd]
			contentStart := strings.Index(descriptionTag, `content="`)
			if contentStart != -1 {
				contentStart += 9 // length of 'content="'
				contentEnd := strings.Index(descriptionTag[contentStart:], `"`)
				if contentEnd != -1 {
					description = strings.TrimSpace(descriptionTag[contentStart : contentStart+contentEnd])
				}
			}
		}
	}

	return title, description
}

// FetchURLPreview is the handler function for the URL preview API
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error":"Invalid JSON"}`)
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error":"URL is required"}`)
		return
	}

	// Create a new HTTP client with timeout
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return fasthttp.DialDualStack(addr)
		},
		MaxIdemponentCallAttempts: 1,
	}

	// Prepare the request
	reqURL := req.URL
	var fastReq fasthttp.Request
	fastReq.SetRequestURI(reqURL)
	fastReq.Header.SetMethod("GET")

	// Set timeout
	timeout := 3 * time.Second

	// Execute the request
	var resp fasthttp.Response
	if err := client.DoTimeout(&fastReq, &resp, timeout); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(fmt.Sprintf(`{"error":"Failed to fetch URL: %v"}`, err))
		return
	}

	// Read response body
	body := resp.Body()
	htmlContent := string(body)

	// Check for successful status code
	statusCode := resp.StatusCode()
	if statusCode != http.StatusOK {
		ctx.SetStatusCode(statusCode)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(fmt.Sprintf(`{"error":"Non-200 status code: %d"}`, statusCode))
		return
	}

	// Extract metadata
	title, description := extractMetaData(htmlContent)

	// Prepare response
	response := MetaData{
		Title:       title,
		Description: description,
	}

	// Marshal response
	jsonResponse, err := json.Marshal(response)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error":"Failed to marshal response"}`)
		return
	}

	// Set response
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	ctx.SetBody(jsonResponse)
}

