			"fec0::/10",  // Site Local (deprecated but still used)
			"::1/128",    // Loopback
			"fe80::/10",  // Link-local
		}

		for _, cidr := range private6 {
			_, block, err := net.ParseCIDR(cidr)
			if err == nil && block.Contains(ip) {
