func (t *Tokenizer) Next() TokenType {
	// Simplified tokenizer implementation
	// In production use golang.org/x/net/html
	// This implementation handles basic cases for title and meta tags
	var buf []byte

	for {
		b := make([]byte, 1)
		n, err := t.r.Read(b)
		if n > 0 {
			buf = append(buf, b[0])
		}
		if err != nil {
			t.eof = true
			break
		}

		// Look for HTML tags
		if len(buf) >= 2 && buf[len(buf)-2] == '<' {
			// Found start of tag
			end := -1
			for i := len(buf) - 1; i < len(buf)+100; i++ {
				if i >= len(buf) {
					// Need more data
					b = make([]byte, 1)
					n, err := t.r.Read(b)
					if n > 0 {
						buf = append(buf, b[0])
					}
					if err != nil {
						t.eof = true
						return ErrorToken
					}
				}

				if buf[i] == '>' {
					end = i
					break
				}
			}

			if end > 0 {
				tagData := string(buf[1:end])
				buf = buf[end+1:]

				// Determine tag type
				if strings.HasPrefix(tagData, "!") {
					continue // Skip comments, doctype, etc.
				}

				tagName := strings.Split(tagData, " ")[0]
				tagName = strings.Trim(tagName, "/")

				if strings.ToLower(tagName) == "title" {
					// Find text content
					var textBuf []byte
					for {
						b = make([]byte, 1)
						n, err := t.r.Read(b)
						if n > 0 {
							textBuf = append(textBuf, b[0])
						}
						if err != nil {
							t.eof = true
							return ErrorToken
						}

						if len(textBuf) >= 7 && string(textBuf[len(textBuf)-7:]) == "</title" {
							// Read until actual closing >
							for {
								b = make([]byte, 1)
								n, err := t.r.Read(b)
								if n > 0 {
									textBuf = append(textBuf, b[0])
								}
								if err != nil {
									t.eof = true
									return ErrorToken
								}
								if b[0] == '>' {
									break
								}
							}
							break
						}
					}
					return TextToken
				} else if strings.HasPrefix(tagData, "meta") || strings.Contains(tagData, "meta ") {
					return StartTagToken
				} else if strings.HasSuffix(tagData, "/") || tagName == "img" || tagName == "br" {
					return SelfClosingTagToken
				} else {
					return StartTagToken
				}
			}
		}
	}

	return ErrorToken
}

